mapper.sql:
/* 이메일 채널 */ SELECT 'EML' AS SNDNG_GBNCD , E.MSG_ID , E.RCVR_ID , E.SNDNG_RSLT_CD , E.SNDNG_DTTM , 'Y' AS SNDNG_YN FROM TB_LMS_MSG_EML_SNDNG E WHERE 1 = 1
AND 'EML' IN
#{gbn}
UNION ALL /* 모바일 채널 (PUSH/ALIMTALK/SMS/LMS) */ SELECT M.MBL_SNDNG_TYCD AS SNDNG_GBNCD , M.MSG_ID , M.RCVR_ID , M.SNDNG_RSLT_CD , M.SNDNG_DTTM , 'Y' AS SNDNG_YN FROM TB_LMS_MSG_MBL_SNDNG M WHERE 1 = 1
AND M.MBL_SNDNG_TYCD IN
#{gbn}
UNION ALL /* 쪽지 채널 */ SELECT 'SHRTNT' AS SNDNG_GBNCD , S.MSG_ID , S.RCVR_ID , 'SUCCESS' AS SNDNG_RSLT_CD , S.SNDNG_DTTM , S.SNDNGYN AS SNDNG_YN FROM TB_LMS_MSG_SHRTNT_SNDNG S WHERE S.SNDNGR_DELYN = 'N'
AND 'SHRTNT' IN
#{gbn}
UNION ALL /* 미발송 예약 메시지 */ SELECT 'RSRV' AS SNDNG_GBNCD , RM.MSG_ID , RT.USER_ID AS RCVR_ID , '' AS SNDNG_RSLT_CD , RM.RSRV_SNDNG_SDTTM AS SNDNG_DTTM , 'N' AS SNDNG_YN FROM TB_LMS_MSG RM INNER JOIN TB_LMS_MSG_RCV_TRGTR RT ON RM.MSG_ID = RT.MSG_ID WHERE RM.RSRV_SNDNG_SDTTM IS NOT NULL AND RM.RSRV_SNDNG_CNCL_DTTM IS NULL AND NOT EXISTS (SELECT 1 FROM TB_LMS_MSG_EML_SNDNG E2 WHERE E2.MSG_ID = RM.MSG_ID) AND NOT EXISTS (SELECT 1 FROM TB_LMS_MSG_MBL_SNDNG M2 WHERE M2.MSG_ID = RM.MSG_ID) AND NOT EXISTS (SELECT 1 FROM TB_LMS_MSG_SHRTNT_SNDNG S2 WHERE S2.MSG_ID = RM.MSG_ID)

mapper.select:
/* SQL ID : MsgSndrDsctnDAO.selectSndrDsctnList 설 명 : 발송내역 목록 조회 */ SELECT * FROM ( SELECT ROWNUM AS RNUM, A.* FROM ( SELECT CH.SNDNG_GBNCD , MSG.MSG_ID , SBJCT.SBJCT_YR , SBJCT.SBJCT_SMSTR , ORG.ORGNM , DEPT.DEPTNM , SBJCT.SBJCTNM , SBJCT.DVCLAS_NO , TRGTR.RCVRNM , (SELECT MAX(UC.CNTCT) FROM TB_LMS_USER_CNTCT UC WHERE UC.USER_ID = CH.RCVR_ID AND UC.CNTCT_TYCD = 'MBL_PHN') AS RCVR_TELNO , CH.SNDNG_DTTM , CH.SNDNG_YN , CH.SNDNG_RSLT_CD FROM (
) CH INNER JOIN TB_LMS_MSG MSG ON CH.MSG_ID = MSG.MSG_ID LEFT JOIN TB_LMS_SBJCT SBJCT ON MSG.SBJCT_ID = SBJCT.SBJCT_ID LEFT JOIN TB_LMS_DEPT DEPT ON SBJCT.DEPT_ID = DEPT.DEPT_ID LEFT JOIN TB_LMS_ORG ORG ON DEPT.ORG_ID = ORG.ORG_ID LEFT JOIN TB_LMS_MSG_RCV_TRGTR TRGTR ON CH.MSG_ID = TRGTR.MSG_ID AND CH.RCVR_ID = TRGTR.USER_ID WHERE 1 = 1
ORDER BY CH.SNDNG_DTTM DESC ) A WHERE ROWNUM <= #{lastIndex} ) WHERE RNUM >= #{firstIndex}

/* SQL ID : MsgSndrDsctnDAO.selectSndrDsctnExcelList 설 명 : 발송내역 엑셀 목록 조회 */ SELECT CH.SNDNG_GBNCD , SBJCT.SBJCT_YR , SBJCT.SBJCT_SMSTR , ORG.ORGNM , DEPT.DEPTNM , SBJCT.SBJCTNM , SBJCT.DVCLAS_NO , TRGTR.RCVRNM , (SELECT MAX(UC.CNTCT) FROM TB_LMS_USER_CNTCT UC WHERE UC.USER_ID = CH.RCVR_ID AND UC.CNTCT_TYCD = 'MBL_PHN') AS RCVR_TELNO , CH.SNDNG_DTTM , CH.SNDNG_YN , CH.SNDNG_RSLT_CD FROM (
) CH INNER JOIN TB_LMS_MSG MSG ON CH.MSG_ID = MSG.MSG_ID LEFT JOIN TB_LMS_SBJCT SBJCT ON MSG.SBJCT_ID = SBJCT.SBJCT_ID LEFT JOIN TB_LMS_DEPT DEPT ON SBJCT.DEPT_ID = DEPT.DEPT_ID LEFT JOIN TB_LMS_ORG ORG ON DEPT.ORG_ID = ORG.ORG_ID LEFT JOIN TB_LMS_MSG_RCV_TRGTR TRGTR ON CH.MSG_ID = TRGTR.MSG_ID AND CH.RCVR_ID = TRGTR.USER_ID WHERE 1 = 1
ORDER BY CH.SNDNG_DTTM DESC

/* SQL ID : MsgSndrDsctnDAO.selectSndrDsctnYrList 설 명 : 발송내역 학사년도 목록 조회 */ SELECT DISTINCT S.SBJCT_YR FROM TB_LMS_SBJCT S INNER JOIN TB_LMS_DEPT D ON S.DEPT_ID = D.DEPT_ID
INNER JOIN TB_LMS_MSG MSG ON MSG.SBJCT_ID = S.SBJCT_ID AND MSG.RGTR_ID = #{userId}
WHERE D.ORG_ID = #{orgId} AND S.DELYN = 'N' ORDER BY S.SBJCT_YR DESC

/*
SQL ID : MsgSndrDsctnDAO.selectSndrDsctnSmstrList
설  명 : 발송내역 학기 목록 조회
*/
SELECT DISTINCT TRIM(S.SBJCT_SMSTR) AS SBJCT_SMSTR
FROM TB_LMS_SBJCT S
INNER JOIN TB_LMS_DEPT D ON S.DEPT_ID = D.DEPT_ID

    INNER JOIN TB_LMS_MSG MSG ON MSG.SBJCT_ID = S.SBJCT_ID AND MSG.RGTR_ID = #{userId}

WHERE D.ORG_ID = #{orgId}
AND S.DELYN = 'N'

    AND S.SBJCT_YR = #{sbjctYr}

ORDER BY TRIM(S.SBJCT_SMSTR) ASC

/* SQL ID : MsgSndrDsctnDAO.selectSndrDsctnDeptList 설 명 : 발송내역 학과 목록 조회 */ SELECT DISTINCT D.DEPT_ID , D.DEPTNM FROM TB_LMS_DEPT D
INNER JOIN TB_LMS_SBJCT S ON S.DEPT_ID = D.DEPT_ID AND S.DELYN = 'N' INNER JOIN TB_LMS_MSG MSG ON MSG.SBJCT_ID = S.SBJCT_ID AND MSG.RGTR_ID = #{userId}
WHERE D.ORG_ID = #{orgId} ORDER BY D.DEPTNM ASC

/*
SQL ID : MsgSndrDsctnDAO.selectSndrDsctnSbjctList
설  명 : 발송내역 운영과목 목록 조회
*/
SELECT DISTINCT S.SBJCT_ID
, S.SBJCTNM
FROM TB_LMS_SBJCT S
INNER JOIN TB_LMS_DEPT D ON S.DEPT_ID = D.DEPT_ID

    INNER JOIN TB_LMS_MSG MSG ON MSG.SBJCT_ID = S.SBJCT_ID AND MSG.RGTR_ID = #{userId}

WHERE D.ORG_ID = #{orgId}
AND S.DELYN = 'N'

    AND S.SBJCT_YR = #{sbjctYr}


    AND TRIM(S.SBJCT_SMSTR) = TRIM(#{sbjctSmstr})


    AND S.DEPT_ID = #{deptId}

ORDER BY S.SBJCTNM ASC
